import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { usePnkListFilterState } from '../../../hooks/usePnkListFilterState';
import { usePnkPermissions } from '../../../hooks/usePnkPermissions';
import { wmsService } from '../../../services/kho/wmsService';
import type { GoodsReceiptDto } from '../../../services/kho/models';
import { VOUCHER_STATUS_OPTIONS } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { pnkPageLabels } from '../../../constants/pnkPageLabels';
import { KHO_PATHS } from '../../../appPaths';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { pollDocumentPostingStatus } from '../../../utils/pollDocumentPostingStatus';
import { canViewWmsInventoryLedger, openWmsListRowMenu } from '../../../utils/wmsListRowMenu';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsSchemaListGrid } from '../../../components/list/WmsSchemaListGrid';
import { buildPnkListToolbar } from '../../../features/kho/wmsVoucherListToolbar';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';
import { WmsPostedInventoryModal } from '../../../components/voucher/WmsPostedInventoryModal';
import {
  VoucherRowActionMenu,
  type VoucherRowMenuAction,
} from '../../../components/voucher-list/VoucherRowActionMenu';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-kho-pnk';
const PAGE_ID = 'kho-pnk';

const PnkListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const { canCreate, canPost, canWrite, canConfirm } = usePnkPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = usePnkListFilterState(LIST_FILTER_SCOPE.pnk);

  const [items, setItems] = useState<GoodsReceiptDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSize] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: GoodsReceiptDto } | null>(null);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);

  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = selection.activeRow;

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      wmsService.getGoodsReceipts({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, pnkPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const handleConfirm = useCallback(async (id: string) => {
    try {
      await wmsService.confirmGoodsReceipt(id);
      dispatchAppToast(dispatch, { message: pnkPageLabels.confirmSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, pnkPageLabels.confirmError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const handlePost = useCallback(async (id: string) => {
    try {
      const enqueued = await wmsService.postGoodsReceipt(id);
      if (enqueued.postingStatus === 'Posted') {
        dispatchAppToast(dispatch, { message: pnkPageLabels.postSuccess, type: 'success' });
        refresh();
        return;
      }
      const final = await pollDocumentPostingStatus(() => wmsService.getGoodsReceiptPostingStatus(id));
      if (final.postingStatus === 'Posted') {
        dispatchAppToast(dispatch, { message: pnkPageLabels.postSuccess, type: 'success' });
      } else if (final.postingStatus === 'Failed') {
        dispatchAppToast(dispatch, {
          message: final.lastError ?? pnkPageLabels.postError,
          type: 'error',
        });
      }
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, pnkPageLabels.postError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const navigateToRow = useCallback((id: string, startInEditMode?: boolean) => {
    navigate(KHO_PATHS.pnkDetail(id), {
      state: startInEditMode ? { startInEditMode: true } : undefined,
    });
  }, [navigate]);

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow?.status === 'Draft' && canWrite;
  const canConfirmActive = Boolean(activeRow?.status === 'Draft' && canConfirm);
  const canPostActive = Boolean(activeRow?.status === 'Confirmed' && canPost);
  const canViewLedgerActive = activeRow ? canViewWmsInventoryLedger(activeRow.status) : false;

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'voucher' as const,
      actions: buildPnkListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: refresh,
        onEditConfig: () => setShowSchemaEditor(true),
        canView: canViewActive,
        onView: () => activeRow && navigateToRow(activeRow.id),
        canEdit: canEditActive,
        onEdit: () => activeRow && navigateToRow(activeRow.id, true),
        canCreate,
        onCreate: () => navigate(KHO_PATHS.pnkThem),
        canViewLedger: canViewLedgerActive,
        onViewLedger: () => setShowLedgerModal(true),
        canConfirm: canConfirmActive,
        onConfirm: () => activeRow && void handleConfirm(activeRow.id),
        canPost: canPostActive,
        onPost: () => activeRow && void handlePost(activeRow.id),
      }),
    }),
    [
      refresh,
      canCreate,
      canViewActive,
      canEditActive,
      canConfirmActive,
      canPostActive,
      canViewLedgerActive,
      activeRow,
      navigate,
      navigateToRow,
      handleConfirm,
      handlePost,
    ],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          navigateToRow(row.id);
          break;
        case 'edit':
          if (row.status === 'Draft' && canWrite) navigateToRow(row.id, true);
          break;
        case 'viewLedger':
          if (canViewWmsInventoryLedger(row.status)) {
            selection.selectActiveRow(row);
            setShowLedgerModal(true);
          }
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, canWrite, navigateToRow],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            placeholder="Số phiếu, NCC, kho, đơn MH…"
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => { setStatus(e.target.value); resetPage(); }}
            options={VOUCHER_STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-filter-status`}
          />
        ),
      },
    ],
    [
      fromDate,
      toDate,
      datePreset,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
    ],
  );

  const listBody = (
    <WmsSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.goodsReceipt}
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      viewMobile={viewMobile}
      emptyLabel={pnkPageLabels.empty}
      selection={selection}
      onRowDoubleClick={r => navigateToRow(r.id)}
      onRowOpenActionMenu={({ row, x, y }) => {
        selection.selectActiveRow(row);
        setRowMenu({ x, y, row });
      }}
    />
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: pnkPageLabels.listTitle,
          titleIconClass: 'fas fa-dolly',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={pnkPageLabels.listSubtitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
            onPageSizeChange={size => {
              setPageSize(size as ListPageSize);
              setPage(1);
              selection.clearActiveRow();
            }}
          />
        )}
        modals={(
          <>
            {activeRow && (
              <WmsPostedInventoryModal
                isOpen={showLedgerModal}
                onClose={() => setShowLedgerModal(false)}
                voucherTitle={`${pnkPageLabels.listTitle} — ${activeRow.code}`}
                testIdPrefix={TEST_ID}
                fetchPostedInventory={() => wmsService.getGoodsReceiptPostedInventory(activeRow.id)}
                fetchPostingStatus={() => wmsService.getGoodsReceiptPostingStatus(activeRow.id)}
              />
            )}
            <ListUiSchemaEditorModal
              testIdPrefix={TEST_ID}
              catalogKind={LIST_UI_SCHEMA_KIND.goodsReceipt}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => { setReloadKey(k => k + 1); }}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView
              showEdit={rowMenu?.row.status === 'Draft' && canWrite}
              showViewLedger
              viewLedgerDisabled={rowMenu ? !canViewWmsInventoryLedger(rowMenu.row.status) : true}
              viewLedgerLabel="Xem sổ kho"
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default PnkListPage;
